16	// TestChaos_MixedConcurrentOps spawns goroutines each running a different
17	// operation against the same store concurrently: create, claim, close, unclaim,
18	// update, append-event. After all goroutines finish the store must be
19	// parseable, have no duplicate IDs, and all beads must have valid statuses.
20	func TestChaos_MixedConcurrentOps(t *testing.T) {
21		forEachChaosBackend(t, func(t *testing.T, s Backend) {
22			// Pre-seed beads that can be operated on.
23			const seedCount = 10
24			seedIDs := make([]string, 0, seedCount)
25			for i := 0; i < seedCount; i++ {
26				b := &Bead{Title: fmt.Sprintf("seed-%d", i)}
27				require.NoError(t, s.Create(b))
28				seedIDs = append(seedIDs, b.ID)
29			}
30	
31			var wg sync.WaitGroup
32			const goroutines = 8
33			const opsPerGoroutine = 20
34	
35			for g := 0; g < goroutines; g++ {
36				g := g
37				wg.Add(1)
38				go func() {
39					defer wg.Done()
40					rng := rand.New(rand.NewSource(int64(g * 1000)))
41	
42					for i := 0; i < opsPerGoroutine; i++ {
43						id := seedIDs[rng.Intn(len(seedIDs))]
44						op := rng.Intn(6)
45						switch op {
46						case 0: // create new
47							nb := &Bead{Title: fmt.Sprintf("g%d-i%d", g, i)}
48							_ = s.Create(nb)
49						case 1: // claim
50							_ = s.Claim(id, fmt.Sprintf("agent-%d", g))
51						case 2: // close
52							_ = s.Close(id)
53						case 3: // unclaim
54							_ = s.Unclaim(id)
55						case 4: // update title
56							_ = s.Update(id, func(b *Bead) {
57								b.Title = fmt.Sprintf("updated-by-g%d-i%d", g, i)
58							})
59						case 5: // append event
60							_ = s.AppendEvent(id, BeadEvent{
61								Kind:    "debug",
62								Summary: fmt.Sprintf("g%d-i%d", g, i),
63							})
64						}
65					}
66				}()
67			}
68	
69			wg.Wait()
70	
71			// Invariants after all concurrent ops.
72			beads, err := s.ReadAll()
73			require.NoError(t, err, "ReadAll must succeed after mixed concurrent ops")
74	
75			validStatuses := []string{StatusOpen, StatusInProgress, StatusClosed}
76	
77			seen := make(map[string]int)
78			for _, b := range beads {
79				seen[b.ID]++
80				assert.NotEmpty(t, b.ID, "bead ID must not be empty")
81				assert.Contains(t, validStatuses, b.Status, "bead %s has invalid status %q", b.ID, b.Status)
82			}
83			for id, count := range seen {
84				assert.Equal(t, 1, count, "bead %s appears %d times (duplicate)", id, count)
85			}
86	
87			// All seed beads must still exist.
88			byID := make(map[string]bool, len(beads))
89			for _, b := range beads {
90				byID[b.ID] = true
91			}
92			for _, id := range seedIDs {
93				assert.True(t, byID[id], "seed bead %s must survive mixed concurrent ops", id)
94			}
95		})
96	}
