98	// TestChaos_ConcurrentClaimContention tests that when multiple goroutines race
99	// to claim the same bead, exactly one succeeds and the rest see an error.
100	func TestChaos_ConcurrentClaimContention(t *testing.T) {
101		forEachChaosBackend(t, func(t *testing.T, s Backend) {
102			const rounds = 20
103			const claimers = 5
104	
105			for round := 0; round < rounds; round++ {
106				b := &Bead{Title: fmt.Sprintf("contended-bead-round-%d", round)}
107				require.NoError(t, s.Create(b))
108				id := b.ID
109	
110				var (
111					wg         sync.WaitGroup
112					successCnt int32
113				)
114	
115				for c := 0; c < claimers; c++ {
116					c := c
117					wg.Add(1)
118					go func() {
119						defer wg.Done()
120						if err := s.Claim(id, fmt.Sprintf("agent-%d", c)); err == nil {
121							atomic.AddInt32(&successCnt, 1)
122						}
123					}()
124				}
125				wg.Wait()
126	
127				// Exactly one claimer must succeed.
128				assert.Equal(t, int32(1), successCnt,
129					"round %d: exactly one goroutine must successfully claim the bead", round)
130	
131				// Bead must be in_progress.
132				got, err := s.Get(id)
133				require.NoError(t, err, "round %d: bead must be readable after claim contention", round)
134				assert.Equal(t, StatusInProgress, got.Status,
135					"round %d: bead must be in_progress after successful claim", round)
136				assert.NotEmpty(t, got.Owner, "round %d: owner must be set after claim", round)
137			}
138		})
139	}
