202	// TestChaos_ConcurrentDepManagement hammers DepAdd/DepRemove concurrently
203	// and verifies the dependency graph is always well-formed (no cycles).
204	func TestChaos_ConcurrentDepManagement(t *testing.T) {
205		forEachChaosBackend(t, func(t *testing.T, s Backend) {
206			// Create a pool of beads.
207			const poolSize = 6
208			pool := make([]string, 0, poolSize)
209			for i := 0; i < poolSize; i++ {
210				b := &Bead{Title: fmt.Sprintf("dep-pool-%d", i)}
211				require.NoError(t, s.Create(b))
212				pool = append(pool, b.ID)
213			}
214	
215			var wg sync.WaitGroup
216			const goroutines = 4
217			const ops = 30
218	
219			for g := 0; g < goroutines; g++ {
220				g := g
221				wg.Add(1)
222				go func() {
223					defer wg.Done()
224					rng := rand.New(rand.NewSource(int64(g * 7)))
225					for i := 0; i < ops; i++ {
226						// Pick two distinct beads.
227						fromIdx := rng.Intn(poolSize)
228						toIdx := rng.Intn(poolSize)
229						if fromIdx == toIdx {
230							continue
231						}
232						from := pool[fromIdx]
233						to := pool[toIdx]
234						if rng.Intn(2) == 0 {
235							_ = s.DepAdd(from, to) // cycle detection may reject
236						} else {
237							_ = s.DepRemove(from, to) // idempotent
238						}
239					}
240				}()
241			}
242			wg.Wait()
243	
244			// Verify no bead has a self-dependency.
245			beads, err := s.ReadAll()
246			require.NoError(t, err)
247			for _, b := range beads {
248				for _, dep := range b.Dependencies {
249					assert.NotEqual(t, b.ID, dep.DependsOnID,
250						"bead %s must not depend on itself", b.ID)
251				}
252			}
253		})
254	}
