256	// TestChaos_WriteAllUnderConcurrentReads verifies that WriteAll under
257	// concurrent ReadAll never produces partial/corrupt reads.
258	func TestChaos_WriteAllUnderConcurrentReads(t *testing.T) {
259		forEachChaosBackend(t, func(t *testing.T, s Backend) {
260			// Seed initial beads.
261			const seed = 20
262			beads := make([]Bead, 0, seed)
263			for i := 0; i < seed; i++ {
264				b := &Bead{Title: fmt.Sprintf("wa-seed-%d", i)}
265				require.NoError(t, s.Create(b))
266				beads = append(beads, *b)
267			}
268	
269			var wg sync.WaitGroup
270			const writers = 3
271			const readers = 5
272			const iterations = 20
273	
274			// Writers: read-then-write under the store lock (simulates normal update traffic).
275			for w := 0; w < writers; w++ {
276				w := w
277				wg.Add(1)
278				go func() {
279					defer wg.Done()
280					for i := 0; i < iterations; i++ {
281						// Use Update to safely mutate one bead (this uses WithLock internally).
282						id := beads[w%len(beads)].ID
283						_ = s.Update(id, func(b *Bead) {
284							b.Notes = fmt.Sprintf("writer-%d-iter-%d", w, i)
285						})
286					}
287				}()
288			}
289	
290			// Readers: ReadAll must always succeed and return parseable beads with non-empty IDs.
291			errCh := make(chan error, readers*iterations)
292			for r := 0; r < readers; r++ {
293				wg.Add(1)
294				go func() {
295					defer wg.Done()
296					for i := 0; i < iterations; i++ {
297						got, err := s.ReadAll()
298						if err != nil {
299							errCh <- err
300							continue
301						}
302						for _, b := range got {
303							if b.ID == "" {
304								errCh <- fmt.Errorf("empty ID in concurrent read")
305							}
306						}
307					}
308				}()
309			}
310	
311			wg.Wait()
312			close(errCh)
313	
314			var errs []error
315			for err := range errCh {
316				errs = append(errs, err)
317			}
318			assert.Empty(t, errs, "concurrent ReadAll must not see corrupt state: %v", errs)
319		})
320	}
