406	// TestChaos_TruncatedJSONLRecovery verifies that if the JSONL file is
407	// truncated mid-line (simulating a crash), ReadAll recovers what it can.
408	func TestChaos_TruncatedJSONLRecovery(t *testing.T) {
409		t.Parallel()
410		s := newTestStore(t)
411	
412		// Create some valid beads.
413		validIDs := make([]string, 0, 5)
414		for i := 0; i < 5; i++ {
415			b := &Bead{Title: fmt.Sprintf("truncation-bead-%d", i)}
416			require.NoError(t, s.Create(b))
417			validIDs = append(validIDs, b.ID)
418		}
419	
420		// Append a truncated (incomplete) JSON line.
421		f, err := os.OpenFile(s.File, os.O_APPEND|os.O_WRONLY, 0o644)
422		require.NoError(t, err)
423		_, _ = f.WriteString(`{"id":"truncated-bead","title":"truncated`) // no closing brace
424		_ = f.Close()
425	
426		// ReadAll must not panic; valid beads should survive (warnings for the bad line).
427		beads, readErr := s.ReadAll()
428		if readErr == nil {
429			byID := make(map[string]bool, len(beads))
430			for _, b := range beads {
431				byID[b.ID] = true
432			}
433			for _, id := range validIDs {
434				assert.True(t, byID[id], "valid bead %s must survive truncated JSONL", id)
435			}
436			// No duplicate IDs.
437			seen := make(map[string]int)
438			for _, b := range beads {
439				seen[b.ID]++
440			}
441			for id, count := range seen {
442				assert.Equal(t, 1, count, "truncated store must not have duplicate %q", id)
443			}
444		}
445		// An error is also acceptable as long as it doesn't panic.
446	}
