524	// TestChaos_DuplicateRowFolding directly tests foldLatestBeads with handcrafted
525	// duplicate scenarios to verify it always keeps the last written row.
526	func TestChaos_DuplicateRowFolding(t *testing.T) {
527		t.Parallel()
528	
529		t.Run("simple duplicate keeps last", func(t *testing.T) {
530			input := []Bead{
531				{ID: "a", Title: "first", Status: StatusOpen},
532				{ID: "a", Title: "second", Status: StatusClosed},
533			}
534			folded := foldLatestBeads(input)
