536			assert.Equal(t, "second", folded[0].Title)
537			assert.Equal(t, StatusClosed, folded[0].Status)
538		})
539	
540		t.Run("interleaved duplicates keep last of each", func(t *testing.T) {
541			input := []Bead{
542				{ID: "a", Title: "a-v1"},
543				{ID: "b", Title: "b-v1"},
544				{ID: "a", Title: "a-v2"},
545				{ID: "b", Title: "b-v2"},
546				{ID: "c", Title: "c-v1"},
547				{ID: "a", Title: "a-v3"},
548			}
549			folded := foldLatestBeads(input)
550			require.Len(t, folded, 3)
